scripts.content:
/**
 * @name Trợ lý kết nối Tơ Hồng 'Dựa trên Cơ Hội'
 * @description Khi độ hảo cảm của nhân vật không phải Tơ Hồng đạt ngưỡng, nút kết nối tự động xuất hiện để ràng buộc.
 * @version 2.0
 * @author Gemini (Translated)
 */

(function () {
    if (typeof SillyTavern === 'undefined' || typeof Mvu === 'undefined' || typeof toastr === 'undefined' || typeof _ === 'undefined' || typeof getScriptButtons === 'undefined' || typeof replaceScriptButtons === 'undefined') {
        console.error("Script này phụ thuộc vào SillyTavern, Mvu, toastr, lodash, và API get/replaceScriptButtons.");
        return;
    }

    const BIND_THRESHOLD = 500; // Ngưỡng hảo cảm, có thể tùy chỉnh
    let activeOpportunities = new Set(); // Lưu trữ key nhân vật đã tạo nút kết nối

    // Hàm cốt lõi: Kiểm tra và cập nhật cơ hội kết nối
    async function checkAndDisplayBindOpportunities() {
        try {
            const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
            if (!mvuData || !mvuData.stat_data) return;

            // [ĐỒNG BỘ BIẾN] Đổi '人脉关系' thành 'MốiQuanHệ'
            const contacts = _.get(mvuData, 'stat_data.MốiQuanHệ[0]', {});
            // [ĐỒNG BỘ BIẾN] Đổi '命运系统.红线对象' thành 'HệThốngVậnMệnh.ĐốiTượngTơHồng'
            const redLineChars = _.get(mvuData, 'stat_data.HệThốngVậnMệnh.ĐốiTượngTơHồng[0]', {});
            const redLineKeys = new Set(Object.keys(redLineChars));

            const currentOpportunities = new Set();

            // 1. Quét tất cả 'MốiQuanHệ' để tìm cơ hội mới
            for (const key in contacts) {
                const contact = contacts[key];
                // [ĐỒNG BỘ BIẾN] Đổi '好感度' thành 'HảoCảm'
                const favor = _.get(contact, 'HảoCảm[0]', 0);

                if (favor >= BIND_THRESHOLD && !redLineKeys.has(key)) {
                    currentOpportunities.add(key);
                }
            }

            // 2. Nếu danh sách cơ hội không đổi, không làm gì cả
            if (_.isEqual(activeOpportunities, currentOpportunities)) {
                return;
            }

            // 3. Cập nhật nút
            let currentButtons = getScriptButtons().filter(btn => !btn.name.startsWith('[❤️ Kết Nối Tơ Hồng:'));

            currentOpportunities.forEach(key => {
                // [ĐỒNG BỘ BIẾN] Đổi '姓名' thành 'Tên'
                const characterName = _.get(contacts[key], 'Tên[0]');
                if (characterName) {
                    const buttonName = `[❤️ Kết Nối Tơ Hồng: ${characterName}]`;
                    currentButtons.push({ name: buttonName, visible: true });

                    // Gán sự kiện click một lần cho nút mới
                    if (!activeOpportunities.has(key)) {
                        eventOnce(getButtonEvent(buttonName), () => handleBindExecution(key, characterName));
                    }
                }
            });

            replaceScriptButtons(currentButtons);
            activeOpportunities = currentOpportunities;

        } catch (error) {
            console.error("【Trợ Lý Tơ Hồng】Lỗi khi kiểm tra:", error);
        }
    }

    // Hàm thực thi kết nối
    async function handleBindExecution(characterKey, characterName) {
        try {
            toastr.info(`Đang kết nối ${characterName} thành Đối Tượng Tơ Hồng...`);
            const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });
            // [ĐỒNG BỘ BIẾN] MốiQuanHệ
            const characterData = _.get(mvuData, `stat_data.MốiQuanHệ[0].${characterKey}`);

            if (!characterData) {
                toastr.error(`Thất bại: Không tìm thấy dữ liệu của ${characterName}.`);
                return;
            }

            const newRedLineCharacter = _.cloneDeep(characterData);
            // [ĐỒNG BỘ BIẾN] '记忆回廊' -> 'HànhLangKýỨc', '日程表' -> 'LịchTrình'
            _.set(newRedLineCharacter, 'HànhLangKýỨc', [{ "$meta": { "extensible": true } }]);
            _.set(newRedLineCharacter, 'LịchTrình', ["", ""]);

            // [ĐỒNG BỘ BIẾN] Cập nhật đường dẫn lệnh
            const assignCommand = `_.assign('HệThốngVậnMệnh.ĐốiTượngTơHồng[0]', '${characterKey}', ${JSON.stringify(newRedLineCharacter)});`;
            const removeCommand = `_.remove('MốiQuanHệ[0]', '${characterKey}');`;

            const newData = await Mvu.parseMessage(`${assignCommand}\n${removeCommand}`, mvuData);

            if (newData) {
                await Mvu.replaceMvuData(newData, { type: 'message', message_id: 'latest' });
                await createChatMessages([{ role: 'system', message: `【Hệ Thống: Vận mệnh của bạn và ${characterName} đã được Tơ Hồng liên kết chặt chẽ.】`, is_hidden: true }]);
                toastr.success(`Đã kết nối thành công ${characterName}!`);
            }
        } catch (error) {
            console.error("【Script Tơ Hồng】Lỗi khi kết nối:", error);
            toastr.error(`Lỗi nội bộ khi kết nối ${characterName}.`);
        }
    }

    // Khởi động lắng nghe
    waitGlobalInitialized('Mvu').then(() => {
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, checkAndDisplayBindOpportunities);
        console.log("【Trợ lý kết nối Tơ Hồng】Đã khởi động và lắng nghe cập nhật biến.");
    });
})();

/**
 * @name Script Giám Sát & Kiểm Tra Cập Nhật Biến AI
 * @description Tự động lắng nghe phản hồi của AI, phân tích lệnh cập nhật biến và kiểm tra kỹ lưỡng trước khi thực thi.
 * @version 1.1
 * @author Gemini (Translated)
 */

(function () {
    if (typeof _ === 'undefined' || typeof toastr === 'undefined') {
        console.error("Script này cần thư viện lodash và toastr.");
        return;
    }

    console.log("【Script Giám Sát Biến】Đã khởi động.");

    async function validateVariableUpdates(lastMessage) {
        if (lastMessage.is_user || !lastMessage.message) {
            return;
        }

        const aiResponseText = lastMessage.message;
        const commandRegex = /_\.(set|add|assign|remove)\(([\s\S]*?)\);/g;
        const commands = [...aiResponseText.matchAll(commandRegex)];

        if (commands.length === 0) return;

        const mvuData = Mvu.getMvuData({ type: 'message', message_id: lastMessage.message_id });
        const stat_data = mvuData?.stat_data;

        if (!stat_data) {
            toastr.warning("Không lấy được stat_data tầng hiện tại, không thể kiểm tra biến.", "Cảnh Báo Script");
            return;
        }

        const errors = [];

        for (const command of commands) {
            const [, commandType, argsString] = command;
            const args = argsString.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(arg => arg.trim());
            const pathString = args[0];
            const path = pathString.substring(1, pathString.length - 1);

            const pathParts = path.replace(/\[(\d+)\]/g, '.$1').split('.');
            const finalKey = pathParts.pop();
            const parentPath = pathParts.join('.');

            switch (commandType) {
                case 'set':
                case 'add':
                    if (parentPath && !_.has(stat_data, parentPath)) {
                        errors.push(`<b>[Đường dẫn không tồn tại]</b> Lệnh <code>_.${commandType}('${path}', ...)</code> có đường dẫn cha <code>'${parentPath}'</code> không tồn tại.`);
                    }
                    else if (!path.endsWith('[0]') && Array.isArray(_.get(stat_data, path))) {
                         errors.push(`<b>[Lỗi tiềm ẩn]</b> Lệnh <code>_.${commandType}('${path}', ...)</code> cố gắng sửa đổi một mảng thay vì giá trị. Có phải ý bạn là <code>'${path}[0]'</code>?`);
                    }
                    break;
                case 'assign':
                    if (!_.has(stat_data, path)) {
                         errors.push(`<b>[Mục tiêu không tồn tại]</b> Lệnh <code>_.assign('${path}', ...)</code> có mục tiêu <code>'${path}'</code> không tồn tại.`);
                    }
                    break;
                case 'remove':
                    if (parentPath && !_.has(stat_data, parentPath)) {
                         errors.push(`<b>[Đường dẫn không tồn tại]</b> Lệnh <code>_.remove('${path}', ...)</code> có đường dẫn cha <code>'${parentPath}'</code> không tồn tại.`);
                    }
                    break;
            }
        }

        if (errors.length > 0) {
            const errorMessage = `
                <div style="max-height: 400px; overflow-y: auto; font-family: sans-serif; font-size: 14px;">
                    <h4 style="margin-top:0;">Phát hiện ${errors.length} vấn đề cập nhật biến tiềm ẩn:</h4>
                    <ul style="padding-left: 20px; margin-bottom: 0;">
                        ${errors.map(e => `<li style="margin-bottom: 8px;">${e}</li>`).join('')}
                    </ul>
                </div>
            `;
            toastr.warning(errorMessage, "Kiểm Tra Cập Nhật Biến", {
                timeOut: 20000,
                extendedTimeOut: 10000,
                closeButton: true,
                tapToDismiss: false,
                "preventDuplicates": true,
            });
        }
    }

    function onMessageReceived(message_id) {
        try {
            const messages = getChatMessages(message_id, { include_swipes: false });
            if (messages && messages.length > 0) {
                validateVariableUpdates(messages[0]);
            }
        } catch (error) {
            console.error("【Script Giám Sát】Lỗi xử lý tin nhắn:", error);
            toastr.error("Lỗi script giám sát biến, xem console để biết chi tiết.", "Lỗi Script");
        }
    }

    waitGlobalInitialized('Mvu').then(() => {
        eventOn(tavern_events.MESSAGE_RECEIVED, onMessageReceived);
    });

})();

/**
 * @name Người Bảo Hộ Hồ Sơ NPC 'Hiệu Chuẩn Thời Gian Thực'
 * @description Tự động kiểm tra và sửa chữa dữ liệu khi AI tạo NPC mới, đảm bảo cấu trúc hoàn chỉnh.
 * @version 2.0
 * @author Gemini (Translated)
 */
(function () {
    if (typeof SillyTavern === 'undefined' || typeof Mvu === 'undefined' || typeof _ === 'undefined') {
        console.error("Script này phụ thuộc SillyTavern, Mvu và lodash API.");
        return;
    }

    // [ĐỒNG BỘ BIẾN] Template NPC 'Tiêu Chuẩn Vàng' - Đã Việt hóa các key
    const npcGoldenTemplate = {
        "Tên": ["Chưa rõ", ""],
        "CấpĐộChiếnLực": ["1(Phàm)", ""],
        "CấpĐộ": [1, ""],
        "ChủngTộc": ["Chưa rõ", ""],
        "ThânPhận": ["Chưa rõ", ""],
        "NghềNghiệp": ["Chưa rõ", ""],
        "TínhCách": ["[Hãy mô tả bằng phong cách thô tục, thẳng thắn]", ""],
        "SởThích": ["[Hãy mô tả]", ""],
        "NgoạiHình": ["[Hãy mô tả bằng phong cách táo bạo, lộ liễu]", ""],
        "TrangPhục": ["[Hãy mô tả]", ""],
        "TrangBị": ["Không", ""],
        "HảoCảm": [50, ""],
        "ĐánhGiá": ["[Hãy điền đánh giá sơ bộ về nhân vật này]", ""],
        "VịTríHiệnTại": ["Chưa rõ", ""]
    };

    let isCorrecting = false;

    async function validateAndCorrectNpcData(mvuData) {
        if (isCorrecting || !mvuData || !mvuData.stat_data) return;

        // [ĐỒNG BỘ BIẾN] '人脉关系' -> 'MốiQuanHệ'
        const contacts = _.get(mvuData, 'stat_data.MốiQuanHệ[0]', {});
        let corrections = {};

        for (const key in contacts) {
            const npc = contacts[key];
            let needsCorrection = false;
            let correctedNpc = _.cloneDeep(npc);

            for (const templateKey in npcGoldenTemplate) {
                if (!_.has(correctedNpc, templateKey)) {
                    correctedNpc[templateKey] = npcGoldenTemplate[templateKey];
                    needsCorrection = true;
                }
            }

            if (needsCorrection) {
                corrections[key] = correctedNpc;
            }
        }

        if (!_.isEmpty(corrections)) {
            isCorrecting = true;
            try {
                let commandString = '';
                for (const key in corrections) {
                    // [ĐỒNG BỘ BIẾN] Cập nhật đường dẫn lệnh
                    commandString += `_.set('MốiQuanHệ[0].${key}', ${JSON.stringify(corrections[key])});\n`;
                }

                const newData = await Mvu.parseMessage(commandString, mvuData);
                if (newData) {
                    await Mvu.replaceMvuData(newData, { type: 'message', message_id: 'latest' });
                    console.log('【Người Bảo Hộ Hồ Sơ NPC】Đã tự động sửa các hồ sơ:', Object.keys(corrections).join(', '));
                    toastr.info(`Đã tự động bổ sung cấu trúc cho ${Object.keys(corrections).length} NPC.`, "Người Bảo Hộ Hồ Sơ NPC");
                }
            } catch (error) {
                console.error("【Người Bảo Hộ NPC】Lỗi khi sửa dữ liệu:", error);
            } finally {
                isCorrecting = false;
            }
        }
    }

    waitGlobalInitialized('Mvu').then(() => {
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, validateAndCorrectNpcData);
        console.log("【Người Bảo Hộ Hồ Sơ NPC】Đã khởi động.");
    });

})();

/**
 * @name Đồng Hồ Thế Giới & Công Cụ Sự Kiện 'Có Sự Sống'
 * @description Giám sát thời gian game và các trạng thái quan trọng, tự động kích hoạt sự kiện thế giới.
 * @version 2.0
 * @author Gemini (Translated)
 */

(function () {
    if (typeof SillyTavern === 'undefined' || typeof Mvu === 'undefined' || typeof toastr === 'undefined' || typeof _ === 'undefined' || typeof getScriptId === 'undefined' || typeof getVariables === 'undefined' || typeof replaceVariables === 'undefined') {
        console.error("Script này phụ thuộc SillyTavern, Mvu, toastr, lodash và API biến script.");
        return;
    }

    // --- Kho Sự Kiện ---
    const worldEvents = {
        daily: [ 
            { tensionDelta: 0, tensionEvent: "Tin Đồn Thương Mại", tensionEffect: "Một tuyến đường buôn bán mới dường như mang lại cơ hội.", newsType: "Bảng Tin Quán Rượu", newsContent: "Có tin đồn rằng, thương đoàn bí ẩn từ phương Đông đã mang đến những loại gia vị và lụa hiếm.", narrative: "【Động Thái Thế Giới: Trong không khí dường như thoang thoảng mùi gia vị lạ, mọi người trong quán rượu đang bàn tán về cơ hội phát tài.】" },
