        }

        // 2. Kích hoạt theo ngưỡng trạng thái
        // [ĐỒNG BỘ BIẾN] Cập nhật đường dẫn
        const currentTension = _.get(mvuData, 'stat_data.ThếGiới.ÁpLựcThếGiới[0].MứcĐộĐeDọa[0]', 0);
        for(const event of worldEvents.tensionThreshold) {
            if (currentTension >= event.threshold && !engineMeta.triggeredTensionEvents.includes(event.tensionEvent)) {
