            }
        }

        // 3. Thực thi cập nhật
        if (eventTriggered) {
            try {
                const newData = await Mvu.parseMessage(commandsToExecute, mvuData);
                if (newData) {
                    await Mvu.replaceMvuData(newData, { type: 'message', message_id: 'latest' });
