                    }
                }
            } catch (error) {
                 console.error("【Script Đồng Hồ Thế Giới】Lỗi thực thi sự kiện:", error);
            }
        }

        await replaceVariables(engineMeta, { type: 'script', script_id: SCRIPT_ID });
    }

    waitGlobalInitialized('Mvu').then(() => {
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, worldClockTick);
        console.log("【Đồng Hồ Thế Giới & Công Cụ Sự Kiện】Đã khởi động.");
    });

})();

