    function getPageContext(limit = 15) {
        try {
            const pWin = window.parent || window;

            // 1. 尝试获取主聊天框 ID
            let chatDiv = pWin.document.getElementById('chat');
            // 兜底：如果没有 #chat，尝试找 body（防止改版）
            if (!chatDiv) chatDiv = pWin.document.body;

            // 2. 获取消息体 (兼容 .mes 和 .message)
            let messages = Array.from(chatDiv.querySelectorAll('.mes'));
            if (messages.length === 0) {
                messages = Array.from(chatDiv.querySelectorAll('.message-body')); // 某些变体
            }

            // 3. 过滤掉莉莉丝面板自己的气泡 (防止递归读取自己)
            messages = messages.filter(m => !m.closest('#lilith-wrapper-cn'));

            return messages.slice(-limit).map(msg => {
                // 获取名字
                let name = msg.getAttribute('ch_name');
                if (!name) {
                    const nameDiv = msg.querySelector('.name_text') || msg.querySelector('.char-name');
                    if (nameDiv) name = nameDiv.innerText;
                }
                name = name || 'User';

                // 获取内容
                let text = '';
                const textEl = msg.querySelector('.mes_text') || msg.querySelector('.message-text');
                if (textEl) {
                    text = textEl.innerText;
                } else {
                    text = msg.innerText; // 暴力兜底
                }

                return { name: name.trim(), message: text.replace(/\n/g, ' ').trim() };
            }).filter(m => m.message.length > 1); // 过滤空消息
        } catch (e) { 
            console.error("Context Error:", e);
            return []; 
        }
    }

