                    let selected = 'mortal';
                    let sum = 0;
                    for (const [key, val] of Object.entries(GachaConfig.tiers)) {
                        sum += val.prob;
                        if (rand <= sum) { selected = key; break; }
                    }
                    results.push(selected);
                }
                return results.sort((a, b) => GachaConfig.tiers[a].prob - GachaConfig.tiers[b].prob);
